{
  "mapping_family_key": "commodity_csv_v1",
  "version": "1.0.0",
  "target_domain": "commodities",
  "applies_to": {
    "parser_kind": "csv_tabular",
    "artifact_kind": "record_ir"
  },
  "entity_rules": [
    {
      "entity_type": "commodity",
      "name_from": "row.commodity_name",
      "alias_from": ["row.commodity_code"],
      "attributes": {
        "category": "row.category",
        "region": "row.region"
      }
    }
  ],
  "metric_rules": [
    {
      "metric_name": "price",
      "subject_entity": {
        "entity_type": "commodity",
        "match_by": "row.commodity_name"
      },
      "value_numeric_from": "row.usd_per_ton",
      "unit_canonical": "USD/ton",
      "measurement_time_from": "row.year",
      "time_granularity": "year",
      "dimensions": {
        "region": "row.region",
        "grade": "row.grade"
      }
    }
  ],
  "normalization_rules": {
    "enum_maps": [
      {
        "field": "row.region",
        "map_key": "world_region_v1"
      }
    ],
    "time_rules": [
      {
        "from": "row.year",
        "parse_as": "year"
      }
    ]
  },
  "validation_rules": [
    {
      "rule_id": "metric.price.value_present",
      "severity": "critical"
    },
    {
      "rule_id": "metric.price.time_present",
      "severity": "error"
    }
  ],
  "quarantine_rules": [
    {
      "condition": "missing(row.commodity_name) || missing(row.usd_per_ton)"
    }
  ],
  "retrieval_artifact_hints": [
    {
      "artifact_type": "timeseries_window",
      "group_by": ["commodity", "region"]
    }
  ]
}

{
  "artifact_kind": "record_ir",
  "schema_hint": "commodity_csv_like",
  "rows": [
    {
      "row_number": 1,
      "fields": {
        "commodity_name": "Copper",
